arguments.file_text:
.chat-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
}

@using sv_3d1b50ec4bf54cceb4d0957d3e2881e4

<div class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    @if (!string.IsNullOrWhiteSpace(Channel.Description))
    {
        <div class="channel-description">@TruncateDescription(Channel.Description)</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }

    private string TruncateDescription(string desc) =>
        desc.Length > 40 ? desc[..40] + "…" : desc;
}

.channel-item {
    padding: 8px 12px;
    cursor: pointer;
    border-radius: 6px;
    margin: 2px 8px;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.15);
}

.channel-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #e0e0e0;
}

.active .channel-name {
    color: #fff;
}

.unread-badge {
    background-color: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-description {
    font-size: 0.78rem;
    color: #999;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
    align-items: flex-end;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-input textarea:focus {
    border-color: #4a76a8;
}

.send-btn {
    padding: 8px 18px;
    background-color: #4a76a8;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    font-size: 0.85rem;
    cursor: pointer;
    transition: background-color 0.15s;
    white-space: nowrap;
}

.send-btn:hover:not(:disabled) {
    background-color: #3a6090;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.emoji-picker {
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 4px 6px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    position: absolute;
    bottom: 100%;
    right: 0;
    margin-bottom: 4px;
    z-index: 10;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    line-height: 1;
    transition: background-color 0.15s;
}

.emoji-btn:hover {
    background-color: #f0f0f0;
}

@using sv_3d1b50ec4bf54cceb4d0957d3e2881e4

@if (Reactions?.Count > 0)
{
    <div class="reaction-bar">
        @foreach (var reaction in Reactions)
        {
            <button class="reaction-badge" @onclick="() => OnReactionClicked.InvokeAsync(reaction.Emoji)"
                    title="@string.Join(", ", reaction.Users)">
                <span class="reaction-emoji">@reaction.Emoji</span>
                <span class="reaction-count">@reaction.Users.Count</span>
            </button>
        }
    </div>
}

@code {
    [Parameter] public List<Reaction>? Reactions { get; set; }
    [Parameter] public EventCallback<string> OnReactionClicked { get; set; }
}

.reaction-bar {
    display: flex;
    gap: 4px;
    flex-wrap: wrap;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    background-color: #f0f4f8;
    border: 1px solid #d8e0e8;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background-color: #dde8f0;
}

.reaction-emoji {
    font-size: 0.9rem;
}

.reaction-count {
    font-weight: 600;
    color: #555;
}

.chat-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
}

