arguments.file_text:
@using sv_3d1b50ec4bf54cceb4d0957d3e2881e4

<div class="message-bubble" @onmouseenter="() => _showActions = true" @onmouseleave="HideActions">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    <ReactionBar Reactions="Message.Reactions" OnReactionClicked="HandleReaction" />

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync()">
            💬 @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="action-bar">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync()" title="Reply in thread">
                💬
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😀
            </button>
            @if (_showEmojiPicker)
            {
                <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public bool Compact { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void HideActions()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        _showActions = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private async Task HandleReaction(string emoji)
    {
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.message-bubble {
    padding: 6px 16px;
    position: relative;
    transition: background-color 0.1s;
}

.message-bubble:hover {
    background-color: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
}

.author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #1a1a1a;
}

.timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.9rem;
    color: #333;
    line-height: 1.45;
    margin-top: 2px;
    white-space: pre-wrap;
    word-wrap: break-word;
}

.thread-link {
    background: none;
    border: none;
    color: #4a76a8;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 4px 0;
    margin-top: 2px;
}

.thread-link:hover {
    text-decoration: underline;
}

.action-bar {
    position: absolute;
    top: -12px;
