    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
}

.action-btn {
    background: none;
    border: none;
    font-size: 1rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    line-height: 1;
}

.action-btn:hover {
    background-color: #f0f0f0;
}

