    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #eee;
}

.thread-header h4 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #666;
    padding: 4px 8px;
    border-radius: 4px;
}

.close-btn:hover {
    background-color: #f0f0f0;
    color: #333;
}

.thread-root {
    padding: 8px 0;
