    border-bottom: 1px solid #eee;
}

.thread-divider {
    padding: 6px 16px;
    font-size: 0.75rem;
    color: #999;
    border-bottom: 1px solid #eee;
}

.thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

