toolArgs.file_text:
@using sv_3d1b50ec4bf54cceb4d0957d3e2881e4

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="area-header">
            <h3># @Channel.Name</h3>
            <span class="header-description">@Channel.Description</span>
        </div>

        <div class="message-list" @onscroll="HandleScroll">
            @if (IsLoadingMore)
            {
                <div class="loading-indicator">Loading older messages…</div>
            }
            @if (Messages is not null)
            {
                @foreach (var msg in Messages)
                {
                    <MessageBubble Message="msg"
                                   ReplyCount="GetReplyCount(msg.Id)"
                                   OnOpenThread="() => OnOpenThread.InvokeAsync(msg.Id)"
                                   OnReact="OnReact" />
                }
            }
        </div>

        <MessageInput Placeholder="@($"Message #{Channel.Name}")" OnSubmit="OnSendMessage" />
    }
    else
    {
        <div class="empty-state">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message>? Messages { get; set; }
    [Parameter] public Dictionary<int, int>? ThreadReplyCounts { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts?.GetValueOrDefault(messageId) ?? 0;

    private async Task HandleScroll(EventArgs e)
    {
        // Scroll-to-top triggers load more via JS interop in the page component.
        // Here we expose the callback; actual scroll detection is on the page.
        await Task.CompletedTask;
    }
}

