arguments.file_text:
@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable
@using sv_3d1b50ec4bf54cceb4d0957d3e2881e4
@using sv_3d1b50ec4bf54cceb4d0957d3e2881e4.Components.Layout

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="sidebar-panel">
        <ChannelSidebar Channels="_channels"
                        ActiveChannelId="_activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-panel @(_threadOpen ? "" : "expanded")">
        <MessageArea Channel="_activeChannel"
                     Messages="_messages"
                     ThreadReplyCounts="_threadReplyCounts"
                     IsLoadingMore="_loadingMore"
                     OnSendMessage="SendMessage"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction"
                     OnLoadMore="LoadMoreMessages" />
    </div>

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <div class="thread-panel-container">
            <ThreadPanel RootMessage="_threadRootMessage"
                         ThreadMessages="_threadMessages"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply"
                         OnReact="HandleReaction" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;

    private List<Message> _messages = new();
    private Dictionary<int, int> _threadReplyCounts = new();
    private bool _loadingMore;
    private int _skip;
    private bool _allLoaded;

    private bool _threadOpen;
    private int? _threadRootId;
    private Message? _threadRootMessage;
    private List<Message>? _threadMessages;

    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<Chat>? _dotNetRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels?.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _jsModule = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-3d1b50ec4bf54cceb4d0957d3e2881e4/Components/Pages/Chat.razor.js");
            await _jsModule.InvokeVoidAsync("initScrollWatcher", ".message-list", _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (_loadingMore || _allLoaded) return;
        await LoadMoreMessages();
        StateHasChanged();
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels?.FirstOrDefault(c => c.Id == channelId);
        _skip = 0;
        _allLoaded = false;
        _messages.Clear();
        _threadReplyCounts.Clear();
        CloseThread();

        var msgs = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = msgs;
        _skip = msgs.Count;
        if (msgs.Count < PageSize) _allLoaded = true;

        CountThreadReplies();

        await ChatService.MarkChannelReadAsync(channelId);
        UpdateChannelUnread(channelId);
    }

    private async Task LoadMoreMessages()
    {
        if (_activeChannelId is null || _loadingMore || _allLoaded) return;

        _loadingMore = true;
        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _skip, PageSize);
        if (older.Count < PageSize) _allLoaded = true;
        _messages.InsertRange(0, older);
        _skip += older.Count;
        _loadingMore = false;

        CountThreadReplies();
    }

    private async Task SendMessage(string content)
    {
        if (_activeChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(_activeChannelId.Value, content, null);
        _messages.Add(msg);
        await ScrollToBottom();
    }

    private async Task OpenThread(int messageId)
    {
        _threadRootId = messageId;
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
        _threadMessages = await ChatService.GetThreadAsync(messageId);
        _threadOpen = true;

        _threadReplyCounts[messageId] = _threadMessages.Count;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootId = null;
        _threadRootMessage = null;
        _threadMessages = null;
    }

    private async Task SendThreadReply(string content)
    {
        if (_activeChannelId is null || _threadRootId is null) return;
        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, content, _threadRootId.Value);
        _threadMessages?.Add(reply);
        _threadReplyCounts[_threadRootId.Value] = _threadMessages?.Count ?? 0;
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
    }

    private void CountThreadReplies()
    {
        // Count messages that are replies to other messages in the current set
        var replyCounts = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());

        foreach (var (rootId, count) in replyCounts)
        {
            _threadReplyCounts[rootId] = count;
        }
    }

    private void UpdateChannelUnread(int channelId)
    {
        if (_channels is null) return;
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = _channels[idx];
            _channels[idx] = ch with { UnreadCount = 0 };
        }
    }

    private async Task ScrollToBottom()
    {
        if (_jsModule is not null)
        {
            await _jsModule.InvokeVoidAsync("scrollToBottom", ".message-list");
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            try { await _jsModule.InvokeVoidAsync("dispose"); }
            catch (JSDisconnectedException) { }
            await _jsModule.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

.chat-container {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
}

.sidebar-panel {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.main-panel {
    flex: 1;
    min-width: 0;
    border-right: 1px solid #ddd;
}

.main-panel.expanded {
    border-right: none;
}

.thread-panel-container {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

let observer = null;
let scrollEl = null;
let dotNetRef = null;

export function initScrollWatcher(selector, ref) {
    dotNetRef = ref;
    scrollEl = document.querySelector(selector);
    if (!scrollEl) return;

    scrollEl.addEventListener('scroll', handleScroll);
    // Scroll to bottom on initial load
    scrollEl.scrollTop = scrollEl.scrollHeight;
}

function handleScroll() {
    if (scrollEl && scrollEl.scrollTop === 0 && dotNetRef) {
        dotNetRef.invokeMethodAsync('OnScrolledToTop');
    }
}

export function scrollToBottom(selector) {
    const el = document.querySelector(selector);
    if (el) {
        el.scrollTop = el.scrollHeight;
    }
}

export function dispose() {
    if (scrollEl) {
        scrollEl.removeEventListener('scroll', handleScroll);
    }
    scrollEl = null;
    dotNetRef = null;
}

