+    private async Task HandleReaction((int MessageId, string Emoji) args)
+    {
+        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
+    }
+
+    private void CountThreadReplies()
+    {
+        // Count messages that are replies to other messages in the current set
+        var replyCounts = _messages
+            .Where(m => m.ReplyToId is not null)
+            .GroupBy(m => m.ReplyToId!.Value)
+            .ToDictionary(g => g.Key, g => g.Count());
+
+        foreach (var (rootId, count) in replyCounts)
+        {
+            _threadReplyCounts[rootId] = count;
+        }
+    }
+
+    private void UpdateChannelUnread(int channelId)
+    {
+        if (_channels is null) return;
+        var idx = _channels.FindIndex(c => c.Id == channelId);
+        if (idx >= 0)
+        {
+            var ch = _channels[idx];
+            _channels[idx] = ch with { UnreadCount = 0 };
+        }
+    }
+
+    private async Task ScrollToBottom()
+    {
+        if (_jsModule is not null)
+        {
+            await _jsModule.InvokeVoidAsync("scrollToBottom", ".message-list");
+        }
+    }
+
+    public async ValueTask DisposeAsync()
+    {
+        if (_jsModule is not null)
+        {
+            try { await _jsModule.InvokeVoidAsync("dispose"); }
+            catch (JSDisconnectedException) { }
+            await _jsModule.DisposeAsync();
+        }
+        _dotNetRef?.Dispose();
+    }
+}
+

